external_knowledge:
- 'product type' refers to the type of financial instrument (e.g., Options, Futures); 
- 'summary of data records' includes total data records, average price, maximum price, and minimum price; 
- 'summary of news articles' includes total news articles and latest news date; 
- 'summary of accesses' includes total accesses and latest access date; 
- 'summary of trends' includes total trends and latest trend date.

sql:
SELECT e.exchange_code, e.exchange_name
FROM exchanges e
WHERE e.contact_email IS NOT NULL AND e.timezone LIKE '%Asia%';

SELECT DISTINCT exchange_code
FROM exchanges
WHERE status != 'closed';
